sql:
SELECT COUNT(con.contribution_id) AS total_contributions_in_ecosystem_modeling
FROM contributions con
WHERE con.area_of_study = 'Ecosystem Modeling';

SELECT AVG(contributions_count) AS avg_contributions_per_contributor
FROM (
    SELECT COUNT(c.contribution_id) AS contributions_count
    FROM contributions c
    GROUP BY c.contributor_id
) AS contributions_summary;

SELECT name
FROM contributors
WHERE born = (SELECT MIN(born) FROM contributors);

SELECT name
FROM contributors
ORDER BY name ASC;

external_knowledge:
* 'scholarly footprint' refers to the total count of a contributor's contributions (total_contributions);
* 'breadth of expertise' is represented by the count of unique areas of study for a contributor's contributions (unique_areas_of_study);
* 'productivity' is measured by the total number of contributions a contributor has made.
